var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"04:47 PM ARC-CR7, 구 공업지대 상공\\n<color=#ffd34c>생활 지구</color>, 강습함 코핀, 코핀 컴퍼니\\nCSE Level 2.","JPN":"04:47 PM ARC-CR7、旧工業地帯上空\\n<color=#ffd34c>生活地区</color>、強襲艦コフィン、コフィンカンパニー\\nCSE Level 2","ENG":"04:47 PM ARC-CR7, Airspace over the Old Industrial Area \\n<color=#ffd34c>Residential Zone</color>, Assault Ship Coffin, Coffin Company\\nCSE Level 2.","TWN":"晚上16:47  ARC-CR7，舊工業地帶上空\\n<color=#ffd34c>生活地球</color>突擊艦科芬，科芬公司\\nCSE Level 2。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야. 탕비실에 있는 게 없네.","JPN":"なにこれ、ショボい休憩室ね。","ENG":"What? There's nothing in the office pantry.","TWN":"什麼，茶水間竟然什麼都沒有。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_10"},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"마리아 아줌마 관사 냉장고도 이것보단 낫겠다.","JPN":"これなら、マリアおばさんとこの冷蔵庫のほうがマシだわ。","ENG":"Aunt Maria's fridge is probably better stocked than this.","TWN":"瑪麗亞大嬸官邸裡的冰箱，也都比這裡好多了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"언니, 마운틴 듀 없어? 콜라는?","JPN":"ねえ、サイダーはないの？　コーラは？","ENG":"Got Mountain Dew, hon? What about Coke?","TWN":"姐姐，沒有雪碧嗎？那可樂呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"두유노우마운틴듀? 두유노우코크?","JPN":"ドゥーユーノウ、サイダー？　ドゥーユーノウ、コーク？","ENG":"Moun-tain-Dew? Co-ca-co-la?","TWN":"不會沒有雪碧，也沒有可樂吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"손님, 여기는 직원 전용 휴게실입니다.","JPN":"お客様、ここは職員専用の休憩室です。","ENG":"I'm sorry, ma'am, but this break room is for company staff only.","TWN":"這位客人，這裡是職員專用的休息室。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"외부인께선 나가 주셔야......","JPN":"部外者の方はご退室を……","ENG":"I'm afraid I have to ask you to leave...","TWN":"外部人員不得入內，請您到外面……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"누가 고물 함선 아니랄까 봐 안에도 썰렁하구만.","JPN":"この艦船は、見た目だけじゃなく中までおんぼろなのか。","ENG":"It's a pretty sad break room if you ask me. Should've expected as much on this piece of junk.","TWN":"這是什麼破舊的艦船，裡面也冷冷清清的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"손님 대접이 이러면 쓰나.","JPN":"客への、おもてなしはどこに行ったんだ。","ENG":"And that's no way to treat your guests.","TWN":"你們都是這樣招待客人的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"제 말이요.","JPN":"まったくですね。","ENG":"I know, right?","TWN":"我的天啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"손님에게 물만 내오는 데가 저희 사무소 말고 또 있었네요.","JPN":"お客様に出すものが水だけだなんて。うちの会社だけだと思ってました。","ENG":"I guess we're not the only company stingy enough to offer just water to their guests.","TWN":"只給客人白開水喝的，原來不是只有我們的事務所，還有其他地方呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"어? 이 TV 가져갈까요?","JPN":"あら？　このテレビ、持って帰りませんか？","ENG":"Huh? Should we take this TV?","TWN":"咦？我們要不要帶走這台電視？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"여긴 보는 사람도 없는 것 같은데.","JPN":"ここには観る人もいなさそうですし。","ENG":"No one's here to stop us, right?","TWN":"這裡好像也沒有人在看。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋은 생각이군.","JPN":"それはナイスアイディアだな。","ENG":"Great idea.","TWN":"真是個好主意。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"TV도 그게 더 행복할 거야.","JPN":"そのほうがテレビも喜ぶだろう。","ENG":"The TV probably prefers you, anyway.","TWN":"有電視看的話會更開心的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저...... 저기......","JPN":"あ……あの……","ENG":"Um... Excuse me...","TWN":"那個……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"여러분......?","JPN":"皆さん……？","ENG":"Hello...?","TWN":"各位……？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아? 혹시 당신이 그 존 메이슨이야?","JPN":"あれ？　もしかして、あんたがあのジョン・メイソン？","ENG":"Huh? Are you John Mason, by any chance?","TWN":"啊，你就是約翰·梅森嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"모터시티에서 온?","JPN":"モーターシティから来たっていう？","ENG":"From Motor City?","TWN":"你是從莫特城來的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"응? 우린 초면인 것 같은데.","JPN":"ん？　初対面だと思ったが。","ENG":"Huh? Have we met before?","TWN":"嗯？我們應該是初次見面啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"날 알고 있나?","JPN":"俺のことを知っているのか？","ENG":"You know who I am?","TWN":"妳認識我？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"알고 말고!","JPN":"知ってるわよ！","ENG":"Of course I know you!","TWN":"當然認識！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자기가 제임스 본드인 줄 아는 느끼한 버터맨에게 한 방 먹여 준 히어로잖아.","JPN":"ジェームズ・ボンド気取りのキザ野郎に一発食らわしたヒーローじゃない。","ENG":"You're the hero who kicked that Sleazeball's butt! The one that thinks he's James Bond or something!","TWN":"聽說你就是像詹姆士龐德一樣，給壞人送上最後一擊的英雄啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내가 그 이야기 듣고 얼마나 통쾌했는지 몰라!","JPN":"その話を聞いたとき、どれだけスカッとしたことか！","ENG":"I became a total fan after hearing that story!","TWN":"我聽到你的事情後，真的是痛快到不行啊！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"올해의 MVP 감이라고.","JPN":"今年のMVP候補ね。","ENG":"You're like the MVP of the year!","TWN":"你就是今年的MVP。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이거 참......","JPN":"こりゃ……","ENG":"Ah...","TWN":"真是的……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 모르게 또 메이슨 용병 사무소의 명성을 떨쳐 버렸군.","JPN":"気づかないうちに、メイソン傭兵事務所の名声を一段と上げちまったな。","ENG":"I guess I ended up furthering the reputation of Mason Mercenary Office without realizing.","TWN":"梅森傭兵事務所的名聲在不知不覺間，已經傳得這麼遠了呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"엉? 우리 회사 이름은 토미와 떨거지들 아니었나?","JPN":"は？　うちの会社名は、「トミーと3バカトリオ」じゃなかったか？","ENG":"Huh? Our company name is Tommy and the Losers!","TWN":"啊？我們公司的名字不是湯米一夥嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"무슨 소리야! 제리의 돌격대지!","JPN":"何言ってんだ。「ジェリー突撃隊」だろ！","ENG":"What! It's Jerry and the Raiders!","TWN":"你在說什麼啦！是傑瑞突擊隊吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"어...... 난 숙명의 미키단인 줄 알았는데......","JPN":"え……俺は「宿命のミッキー団」だと思ってたんだが。","ENG":"Uh... I'm pretty sure it was the Mickey's Gang of Twilight...","TWN":"呃……我一直以為是宿命的米奇團……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......너넨 대체 왜 아직도 따라 다니는 거야?","JPN":"……お前ら、なんでまだついてくるんだ？","ENG":"Why the hell are you still following me?","TWN":"……你們怎麼還跟著我啊？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이젠 얻어먹을 것도 없잖아? 제발 좀 가라, 가!","JPN":"もう何も出てこないぞ？　頼むから、もう行けって！","ENG":"I have nothing else to give you! Leave me alone already!","TWN":"你們現在也沒什麼東西可以拿了啊？快滾吧，滾！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"당신들 전부 나가욧!!!","JPN":"あなたたち、全員出ていきなさいっ！！！","ENG":"All of you get out!","TWN":"你們都給我出去！！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......대체 언제부터 이 고물 함선이 시장바닥으로 변해 버린 거지?","JPN":"……いったい、いつからこのおんぼろ艦船がお祭り騒ぎになってしまったんだ？","ENG":"What's with the crowd?","TWN":"……到底是從什麼時候開始，這艘舊艦船突然變成菜市場了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 전 사람이 많아지니까 활기찬 느낌이 들어서 좋은데요?","JPN":"ははっ。僕は人が増えて、賑やかな感じが気に入ってますけどね。","ENG":"Haha. I kind of like having more folks around. Keeps things energetic.","TWN":"哈哈。人一多就會變得很熱鬧，這感覺很不錯呀？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 이렇게 손님들이 많이 드나들다 보면, 조만간 탕비실에 물 말고 다른 음료수도 비치되지 않을까요?","JPN":"それにこうやってお客さんが増えたら、いつか休憩室に水以外の飲み物も用意されるんじゃないですか？","ENG":"And if we get more visitors like this, don't you think they'll start stocking the break room with better drinks?","TWN":"而且只要出入公司的客人變多，我們的茶水間之後除了水，也會開始準備其他飲料吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그런 방탕한 미래는 결코 오지 않을 거라고 약속할 수 있네, 시윤 군.","JPN":"……そんなぜいたくな未来は、決して来ないと約束するわ、アキヤマ君。","ENG":"I can assure you that the company will never engage in such ostentatious behavior, Shiyoon.","TWN":"……我保證，這個奢侈的未來永遠不會發生，時雲君。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 오셨네요. 부사장님.","JPN":"あ、副社長、お疲れ様です。","ENG":"Oh, hello. Madame Vice President.","TWN":"啊，您來了啊。副總。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"잘 왔다, 이수연.","JPN":"よくきたな、カナミ。","ENG":"Good timing, Sooyeon.","TWN":"妳來得正好，李秀妍。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 이것들 다 뭐야? 새로 뽑은 대원들은 아닌 것 같은데.","JPN":"一体こいつらは何なんだ？　新しい隊員ではなさそうだが。","ENG":"Who are these guys? Don't tell me they're new recruits.","TWN":"這是在搞什麼鬼？他們看起來不像是新來的隊員啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 물론 우리 우수사원님의 훌륭한 성과 덕분이죠.","JPN":"それはもちろん、うちの優秀社員さんの素晴らしい成果の賜物ですよ。","ENG":"This is all thanks to our Employee of the Month.","TWN":"這當然要歸功於本公司的優秀新人，米娜小姐啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......내가?","JPN":"……私のこと？","ENG":"...Me?","TWN":"……我？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지난번 작전에서 저희의 활약에 큰 인상을 받은 고객님의 주선으로, 미 국방성 산하 기관에서 연락이 왔습니다.","JPN":"前回の作戦で我々の活躍に感銘を受けたお客様からのご紹介で、アメリカ国防省傘下の機関から連絡がありました。","ENG":"Our client was greatly impressed with our performance on the last mission and set us up with another organization under the States' Department of Defense.","TWN":"在上次作戰中，客戶對我們的表現印象非常深刻。所以在客戶的安排下，美國國防部的分支機構連絡了我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 그쪽에서 지명한 일부 인원들을 이번 작전에 참가시키는 조건으로 추가 의뢰를 맡기고 싶다는 제안을 받았습니다.","JPN":"そして、あちらから指名された一部メンバーを今回の作戦に参加させるという条件付きで、追加依頼をしたいとの提案がありました。","ENG":"They decided to entrust us with another mission if we agree to use some of their employees.","TWN":"然後，對方以指定的部分人員參加此次作戰為條件，向我們提出了追加委託的提案。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말해, 이제 저희 회사도 정부 부처 수주를 받는 입장이 된 거죠.","JPN":"つまり、今や我が社は、政府機関の仕事を受注する立場になっているのです。","ENG":"In other words, this company is now a government contractor.","TWN":"換句話說，我們公司現在也能接到政府部門的訂單了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 거지 같은 회사에서 착취당한 지 십수 년째.","JPN":"このクソみたいな会社に搾取されつづけて、十数年。","ENG":"After decades of slaving away in this dump...","TWN":"被這個像乞丐一樣的公司剝削了十幾年。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"드디어 저도 빛을 볼 때가 온 것입니다.","JPN":"ついにこの私にも春が訪れたのです。","ENG":"It's finally time for me to harvest the fruits of my labor!","TWN":"我終於看到了一線曙光了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......누가 들으면 그동안 노예 생활이라도 한 줄 알겠군.","JPN":"……誰かが聞いたら、今まで奴隷生活でも送っていたと思うだろうな。","ENG":"The way you sound, people might take you literally.","TWN":"……無論是誰聽了妳的話，都會覺得妳以前是不是當過奴隸呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런데 전에는 정보부 일은 골치 아파서 안 받는다고 하지 않았어?","JPN":"だが、情報局の仕事は厄介だから受けないと言っていなかったか？","ENG":"Didn't you always say working with the spooks is a pain in the neck?","TWN":"但是妳以前不是說過情報部的工作很讓人頭痛，一點都不想接嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 내용인지 듣기는 하고 수락한 거냐?","JPN":"内容はちゃんと確認してから受けたんだろうな？","ENG":"Did you even hear out what the mission entails before you accepted?","TWN":"妳有先問過工作內容是什麼嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아뇨.","JPN":"いいえ。","ENG":"No.","TWN":"沒有。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"내용이 뭐든 거절할 수 없는 액수를 제시 받았다고만 말해 두겠습니다.","JPN":"内容が何であれ、断れない金額を提示された、とだけ言っておきますね。","ENG":"Let's just say they made me an offer I couldn't refuse...","TWN":"不管內容是什麼，我只知道我們收到了一筆令人無法拒絕的金額。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 매우 흡족해하시더군요.","JPN":"社長が大変喜んでおられました。","ENG":"The president was very pleased with the news.","TWN":"老闆他非常滿意。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"둠칫♪ 둠칫♬","JPN":"ズンチャ♪　ズンチャ♬","ENG":"Boom ♪ Boom ♪","TWN":"咚鏘♪咚鏘♬"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"헤이! 아미-고!","JPN":"ヘ～イ！　アミーゴ！","ENG":"Hey! Amigos!","TWN":"嘿！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"자네들의 열정과 헌신으로 회사가 나날이 발전하고 있네! 기쁜 일이군!","JPN":"君たちの情熱と献身のおかげで、わが社が日に日に成長している！　喜ばしいことだ！","ENG":"The company is flourishing by the day! It's all thanks to your hard work and dedication! What a joyful occasion!","TWN":"各位的工作熱情以及服務犧牲精神，使得我們公司的業績步步高升！真是令人高興啊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"앞으로도 잘 부탁하네!","JPN":"これからもよろしく頼む！","ENG":"Keep up the good work!","TWN":"以後也請各位多多加油囉！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......그 잡동사니들은 다 뭐야?","JPN":"……そのがらくたは、何だ？","ENG":"...What's with all the junk?","TWN":"……那些雜七雜八的破爛是什麼?"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설마 회사 공금으로 산 건 아니겠지?","JPN":"まさか会社の金で買ったんじゃないだろうな？","ENG":"Don't tell me you bought it with company money...","TWN":"該不會是用公款買的吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"그, 그, 그...... 그런 일은...... 이, 있을 수가 어, 없네!","JPN":"そそそ……そんなことは……あ、あるはずない！","ENG":"Err... Don't be ridiculous! That's unthinkable! Preposterous!","TWN":"這、這、這……這種事情……怎麼可能嘛！才不會呢！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"나, 나는 사업상 급한 약속이 있어서...... 이, 이만......","JPN":"わ、私はビジネスで急ぎの約束があるのだ……この辺で失礼……","ENG":"Well, I have a very important business meeting so... See you around!","TWN":"我、我正好有個緊急會議……那就先聊到這裡啦……."},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"Yo! 췌키라웃! 나는 황금의 머신-갑, 가난한 너는 저리-가, 내 비트에 홀려 다들 따라-가, 나의 배짱이 궁금하면 너도 통장-까.","JPN":"Yo！　チェケラ！　私は黄金のマシーン-甲-、貧しい君はあっち行こう、私のビートに魅せられた奴はついてこう、私の度胸が気になるなら君も腹くくろう。","ENG":"Yo! Check it out! The name's Machine Gap! Poor folks are full of crap! My body's made of gold but my rap's got soul! Throw your hands in the air like a billionaire!","TWN":"YO！ACTION！我是黃金的-機械-我超帥～！貧窮的你，被我的節奏迷住-了-嗎？大家都跟著我-走-吧！如果想測試一下膽量-的-話，你拿出存款也-OK-的-喔！？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......역시 처음 봤을 때 부숴 버렸어야 했어.","JPN":"……やはり初対面の時、ぶち壊すべきだった。","ENG":"...I should have crushed that thing while I had the chance.","TWN":"……果然，當初見到這東西的時候就該打爛它的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님도 지금 들었지?","JPN":"副社長も今の聞いたよね？","ENG":"Did you hear that, Vice President?","TWN":"副總您也聽到了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저거 부서지면 수리비는 소대장 급여에서 제하는 걸로 확실히 하고 넘어가자고.","JPN":"あれが壊れたら、修理費は小隊長の給与から差し引いてね。","ENG":"If anything happens to Machine Gap, you know whose paycheck to dock for the repairs.","TWN":"如果那個被打爛的話，修理費請從小隊長個人的薪資中扣除。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양도 이제 저희 회사에 완벽히 적응한 것 같군요.","JPN":"ミナさんも、わが社にすっかり馴染んだみたいですね。","ENG":"I think you're adjusting to our company culture quite well, Mina.","TWN":"米娜小姐似乎已經完全適應我們公司了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 쿠퍼 양.","JPN":"では、クーパーさん。","ENG":"Now, Ms. Cooper.","TWN":"那麼庫博小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미션 브리핑을 부탁하겠습니다.","JPN":"ミッションの説明をお願いします。","ENG":"Please proceed with the mission briefing.","TWN":"請妳簡要說明一下任務。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오케이, 내 턴이네.","JPN":"オーケー、アタシの番ね。","ENG":"Alrighty. I guess it's my turn.","TWN":"那換我囉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"안녕, 코핀 여러분.","JPN":"コフィンの皆さん、はじめまして。","ENG":"Greetings, Coffin Company.","TWN":"你們好啊，科芬的各位。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내 이름은 실비아 레나 쿠퍼.","JPN":"アタシの名前は、シルビア・レナ・クーパー。","ENG":"My name is Sylvia Lena Cooper.","TWN":"我的名字叫希爾維亞·蕾娜·庫博。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그냥 실비아라고 불러 줘.","JPN":"シルビアって呼んでね。","ENG":"But you can just call me Sylvia.","TWN":"叫我希爾維亞就可以了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"레나 양과 미들 네임이 같군요.","JPN":"レナとミドルネームが同じですね。","ENG":"You have the same middle name as Lena.","TWN":"她和蕾娜小姐的中間名是一樣的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"순결한 두 소녀에게서 운명의 양자 얽힘이 느껴집니다.","JPN":"純潔な二人の少女から、運命の量子のもつれを感じます。","ENG":"I can sense the fate of two innocent girls entangling in the cosmos...","TWN":"從這兩位純真的少女身上，我可以感受到命運量子的糾纏。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......운명의 뭔 얽힘?","JPN":"……運命の、なんのもつれだって？","ENG":"...Entangling in the what?","TWN":"……命運什麼的糾纏？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"모르시는군요.","JPN":"ご存じないのですね。","ENG":"Oh, you don't know?","TWN":"原來妳不知道啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"넷튜브에서 초끈양자운명점성술이라는 영상을 찾아 보세요.","JPN":"ネットチューブで「超紐量子運命占星術」という動画を探してみてください。","ENG":"Just search \\"Superstring Quantum Astrology\\" on NetTube and you'll see what I mean.","TWN":"請在網上找搜尋一個叫作“超級量子命運占星術”的影片。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"레나 양처럼 꽉 막힌 사람도 이젠 점성술이 과학적으로 증명이 가능한 실존학문이라는 사실을 받아들여야 할 때입니다.","JPN":"レナのように融通が利かない人も、今や占星術は科学的に証明できる実存学問だということをそろそろ受け入れるべきです。","ENG":"It's time for people to start accepting the fact that astrology is a scientifically verified field... Especially high-strung people like you.","TWN":"像蕾娜小姐這種思想僵化的人，也該接受占星術是經得起科學證明的事實。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......제목만 들어도 아주 교과서적인 사이비 같은데.","JPN":"……タイトル聞いただけでも、典型的なインチキの匂いがするんだけど。","ENG":"...Sounds like a cult to me.","TWN":"……只聽標題就覺得是什麼冒牌的教科書。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"아직도 그런 불경한 소리를 하다니!","JPN":"またそんな不謹慎なことを言って！","ENG":"How dare you speak such heresy!","TWN":"到現在還在說這種不敬的話！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이 이단자!","JPN":"この異端者！","ENG":"You're the cultist!","TWN":"妳這個異端。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정식 소속은 미 국방꼰대부 아래의 블라블라블라 엄청 복잡한 이름인데.......","JPN":"正式な所属名はアメリカ国防省の偉そうな部の、なんちゃらかんちゃらのすごく複雑な名前なんだけど……","ENG":"My official affiliation is with a group under the DoD. We have a very long winded name so...","TWN":"我的正式所屬單位是美國國防部底下的什麼什麼的，但因為名字非常複雜……."},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"보통은 다 생략하고 그냥 <color=#ffd34c>델타 세븐</color>이라고 불러.","JPN":"普段は省略して、<color=#ffd34c>デルタセブン</color>と呼んでるわ。","ENG":"Everyone just calls us <color=#ffd34c>Delta Seven</color>.","TWN":"通常會省略全部名稱，只稱為<color=#ffd34c>第七三角洲部隊</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"델타 세븐?","JPN":"デルタセブン？","ENG":"Delta Seven?","TWN":"第七三角洲部隊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전략특수전사령부 제 7 델타분견대</color>의 약칭입니다.","JPN":"<color=#ffd34c>戦略特殊戦司令部第7デルタ支隊</color>の略称です。","ENG":"It's short for the <color=#ffd34c>7th Delta Detachment of the Strategic Special Operations Command</color>.","TWN":"<color=#ffd34c> 戰略特戰部隊司令部-第7三角洲分遣隊</color>的簡稱。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"흔히들 말하는 델타포스의 카운터 능력자 특수부대라고 보면 됩니다.","JPN":"いわゆるデルタフォースのカウンター特殊部隊だと思ってください。","ENG":"Think of them as the Counter version of Delta Force.","TWN":"可以當作是人們常說的第七三角洲部隊的制裁者特種部隊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......영화에서 보던 거랑은 이미지가 다른데.","JPN":"……映画で見たのとはちょっとイメージ違うな。","ENG":"She doesn't look anything like those guys from the movies.","TWN":"……和我在電影中看到的不太一樣啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 근육마초 멍청이들이랑은 엮지 말아 줄래?","JPN":"あの筋肉バカどもと一緒にしないでくれる？","ENG":"Can you please not associate me with those meatheads?","TWN":"請不跟把我和那些肌肉笨蛋相提並論好嗎？ "},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"같은 부대라고 해도 난 근육이 아니라 지성을 무기로 삼는 엘리트 요원이거든.","JPN":"同じ部隊でも、アタシは筋肉じゃなく知性で戦うエリート要員なんだから。","ENG":"We might be on the same team, but I'm an elite agent who uses intelligence over brute force.","TWN":"就算是同一個部隊，我不是用肌肉，而是用知性當作武器的精英要員。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아...... 네. 물론 그러시겠죠.","JPN":"あ……はい。もちろん、そうだろうね。","ENG":"Uh... Sure. Of course you are.","TWN":"啊……是，當然了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 지난번 리플레이서 테러 사건에서 얻은 베리칩을 해독해 봤는데, 여기에 있던 정보가 아주 대박이더라고!","JPN":"まあとにかく、この前のリプレイサーテロ事件で入手したベリーチップを解読してみたんだけど、これが大当たりだったのよ！","ENG":"Anyway. We analyzed the VeriChip from the Replacer terrorist incident, and we found something very interesting!","TWN":"總之，我破解了上次克隆集團恐怖襲擊事件中獲得的超級晶片，結果裡面的資訊非常驚人！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"엉클 샘이 눈에 불을 켜고 찾아 다니는 물건을 이 리플레이서라는 녀석들이 발견한 모양이거든.","JPN":"アンクル・サムが目を光らせて探していたものを、このリプレイサーってのが見つけたみたい。","ENG":"It looks like those Replacers found something Uncle Sam had his eye on for years!","TWN":"這群叫作克隆集團的家伙們，好像發現了山姆大叔不斷在尋找的東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 테러리스트 조직의 정보를 그냥 믿기도 그렇고......","JPN":"だけど、テロリスト組織の情報を鵜吞みにするわけにもいかないし……","ENG":"But since we have to take intel from a terrorist group with a grain of salt...","TWN":"但我們也不能就這樣相信恐怖份子組織的情報……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"확실한 증거도 없이 영토 밖에서 작전을 진행하는 것도 그림이 좀 이상하잖아?","JPN":"確かな証拠もないのに領土外で作戦を進めるのも、絵がしっくりこないでしょ？","ENG":"We can't go on a mission in areas outside of our jurisdiction without definite proof, right?","TWN":"沒有十分把握的情況下，在自己的領土外展開作戰，這種計畫也太不可靠了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"해서, 높으신 분들이 관리국이랑 싸바싸바를 한 끝에 당신들이 낙찰된 거지.","JPN":"そこでお偉いさんたちが管理局と裏でやり取りした結果、あんたたちを落札したってわけ。","ENG":"So... The top brass worked things out with the Administration and they ended up choosing you guys for the job!","TWN":"所以我們的高層向管理局拍馬屁，才讓最後你們贏得這次的競標。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 참고로 이건 칭찬이야.","JPN":"あ、ちなみに、これ褒めてるんだからね？","ENG":"That was a compliment, by the way.","TWN":"啊，順帶一提，這是一種讚美。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우리가 원래는 눈이 꽤 높거든.","JPN":"アタシたちって、ほら、すごくお目が高いのよ？","ENG":"We set the bar very high for our candidates.","TWN":"我們的眼光是很挑剔的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......훌륭한 사냥개라고 칭찬해 주다니 황송해서 몸 둘 바를 모르겠군.","JPN":"……優れた猟犬だと褒めてくださるとは、恐れ多くて困ってしまうな。","ENG":"So you're saying we make excellent hound dogs. Some compliment.","TWN":"……居然誇我們是優秀的獵犬，這還真是不敢當呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님은 세상을 너무 삐딱하게 보시는 것 같아요.","JPN":"師匠は、本当ひねくれ者ですね。","ENG":"Always the cynic, Master.","TWN":"師父妳對這個世界太嚴厲了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 나쁘지 않은데요?","JPN":"僕は別に悪くない話だと思いますけど。","ENG":"I, for one, don't mind this at all!","TWN":"我們還不錯吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"멍멍!","JPN":"わんわん！","ENG":"Woof, woof!","TWN":"汪汪！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐가 됐든 보수만 잘 나온다면 나도 좋아.","JPN":"なんであれ、報酬がいいんなら私も賛成。","ENG":"I don't care as long as the pay is good.","TWN":"反正不管怎樣，只要報酬豐厚，我就高興。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 우리가 할 일이 뭐지?","JPN":"それで、私たちの任務は何？","ENG":"So what do we have to do?","TWN":"所以我們要做什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좋아! 그런 캐피탈리즘한 마음가짐이 아주 마음에 들어.","JPN":"そうこなくちゃ！　そんな資本主義万歳な態度、とても気に入ったわ。","ENG":"Alright! I love your capitalistic spirit!","TWN":"很好！我就喜歡妳這種開朗樂觀的心態。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 더 자세한 건 나름 기밀이라서 말이지.","JPN":"でもこれ以上の詳細は機密なの。","ENG":"But the details are actually classified...","TWN":"但詳細內容目前還算是機密。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정말 우리가 찾는 물건이 있으면 그때 설명하는 걸로 할게.","JPN":"我々が探すべきものが見つかったら、その時に説明することにするわね。","ENG":"I'll tell you guys more once we confirm that the item is actually there.","TWN":"如果我們真的發現要找的東西，到時候會再跟你們說明的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 일단 출발해 볼까?","JPN":"それじゃあ、とりあえず出発しましょうか？","ENG":"Let's just get going for now, shall we?","TWN":"那我們現在就先出發吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"브리핑은 이상입니다.","JPN":"ブリーフィングは以上です。","ENG":"That's it for the briefing.","TWN":"以上的內容就是簡要說明了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"본 함은 30분 뒤에 작전지점으로 출격합니다.","JPN":"本艦は30分後に作戦地点に出撃します。","ENG":"This ship will head out to the area of operations in 30 minutes.","TWN":"本艦30分鐘後會在作戰點出擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다들 준비하세요.","JPN":"皆さん、準備をはじめてください。","ENG":"Everyone get ready!","TWN":"請所有人都做好準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......일이 복잡하게 흘러가는 것 같은데.","JPN":"……なんだか複雑な流れ。","ENG":"...Things are getting more and more complicated.","TWN":"……事情好像變得很複雜。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장 생각은 어때?","JPN":"隊長はどう思う？","ENG":"What do you think, Cap?","TWN":"隊長妳怎麼想？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"세상 일이라는 게 어쩔 수 없는 것도 있는 법이지.","JPN":"世の中には、やむを得ないこともあるのよね。","ENG":"We can't always have things go our way. That's the way of the world.","TWN":"這世上，也有我們無能為力的事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어쩌면 우리에게도 그리 나쁘지만은 않을 수도 있어, 린.","JPN":"もしかしたら私たちにとっても、そこまで悪いことばかりではないかもよ、リン。","ENG":"Then again, this might not be all that bad for us, Lin.","TWN":"對我們來說，這大概也不是什麼不好的事情，琳。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어차피 한 번 마주친 이상, 녀석들과는 어떻게든 끝을 봐야 할 테니까.","JPN":"一度戦ったからには、どのみち奴らとはケジメをつけないとだし。","ENG":"We got involved with them, so we have to see an end to it sooner or later.","TWN":"既然都已經遇到他們了，那我們總得和他們做個了結。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장 말이 맞아!","JPN":"隊長の言うとおりだぜ！","ENG":"She's right!","TWN":"隊長說得對！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그 자식들, 지난번에도 별거 없었잖아?","JPN":"あいつら、この前も大したことなかったじゃん？","ENG":"Those punks hardly put up a proper fight last time.","TWN":"那些傢伙，上次也沒什麼了不起的吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"우리가 너무 걱정하고 있었던 걸지도 몰라.","JPN":"俺らは必要以上に心配してたかもしれない。","ENG":"We might be getting worried over nothing.","TWN":"說不定我們太過操心了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"나이트에게 한방 처 맞고 별똥별처럼 날아가던 누군가께서 대체 무슨 근본 없는 자신감으로 큰소리 탕탕 치는지 모르겠네.","JPN":"ナイトに一発食らって流れ星のように飛んでった誰かさんが何を言ってるんだか。","ENG":"That's a lot of confidence coming from someone who flew away like a comet after one blow from the Knight.","TWN":"被那個騎士一拳打飛變成天上流星的傢伙，到底是哪來的自信說這種話。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야! 너 말 다했냐?","JPN":"おい！　お前なんつった？","ENG":"Hey! You want a piece of me?","TWN":"喂！妳嗆爽沒？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이리 와! 이리 와 보라고!","JPN":"ちょっと来いよ！　来いっつってんだろうが！","ENG":"Get over here! I said get over here!","TWN":"過來啊！有種就過來啊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"......대장.","JPN":"……隊長。","ENG":"...Cap.","TWN":"……隊長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜찮아.","JPN":"大丈夫よ。","ENG":"It's fine.","TWN":"不要緊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우리도 그동안 놀고 있었던 게 아니야.","JPN":"私たちもこれまで遊んでたわけじゃないんだから。","ENG":"It's not like we were twiddling our thumbs this whole time.","TWN":"我們這一路走來，不是都只有在玩而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우린 강해. 충분히 이겨낼 수 있어.","JPN":"私たちは強い。十分に勝てる。","ENG":"We're strong. We can win.","TWN":"我們很強的，一定能打敗他們！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"날 믿어, 소빈아.","JPN":"私を信じてね、コハル。","ENG":"Trust me, Sobin.","TWN":"相信我，素蘋。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};